contracts/farkle/AkibaFarkleTicketManage.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";

interface IAkibaMilesBurnable {
    function burn(address account, uint256 amount) external;
}

/// @title AkibaFarkleTicketManager
/// @notice AkibaMiles-based non-transferable game tickets for Farkle Quick Duel.
///         5 tickets = 25 AkibaMiles (configurable).
/// @dev UUPS upgradeable.
contract AkibaFarkleTicketManager is
    Initializable,
    OwnableUpgradeable,
    ReentrancyGuardUpgradeable,
    UUPSUpgradeable
{
    IAkibaMilesBurnable public akibaMiles;
    address public settlementManager;

    uint256 public ticketsPerPack;
    uint256 public milesPerPack;
    uint256 public maxTicketBalance;

    mapping(address => uint256) public ticketBalance;

    event TicketsPurchased(address indexed user, uint256 ticketAmount, uint256 milesBurned);
    event TicketsDebited(address indexed user, uint256 amount, bytes32 indexed reason);
    event TicketsGranted(address indexed user, uint256 amount, bytes32 indexed reason);
    event SettlementManagerUpdated(address newManager);
    event PackConfigUpdated(uint256 tickets, uint256 miles);

    error InsufficientTickets();
    error ExceedsMaxBalance();
    error Unauthorized();
    error ZeroAddress();

    modifier onlySettlement() {
        if (msg.sender != settlementManager) revert Unauthorized();
        _;
    }

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() { _disableInitializers(); }

    function initialize(address _akibaMiles) external initializer {
        if (_akibaMiles == address(0)) revert ZeroAddress();
        __Ownable_init();
        __ReentrancyGuard_init();
        __UUPSUpgradeable_init();

        akibaMiles      = IAkibaMilesBurnable(_akibaMiles);
        ticketsPerPack  = 5;
        milesPerPack    = 25e18;
        maxTicketBalance = 50;
    }

    function _authorizeUpgrade(address) internal override onlyOwner {}

    // ── User actions ──────────────────────────────────────────────────────────

    /// @notice Buy one pack by burning AkibaMiles.
    function buyTicketPack() external nonReentrant {
        uint256 newBalance = ticketBalance[msg.sender] + ticketsPerPack;
        if (newBalance > maxTicketBalance) revert ExceedsMaxBalance();
        akibaMiles.burn(msg.sender, milesPerPack);
        ticketBalance[msg.sender] = newBalance;
        emit TicketsPurchased(msg.sender, ticketsPerPack, milesPerPack);
    }

    // ── Settlement manager actions ────────────────────────────────────────────

    function debitTickets(address user, uint256 amount, bytes32 reason) external onlySettlement {
        if (ticketBalance[user] < amount) revert InsufficientTickets();
        unchecked { ticketBalance[user] -= amount; }
        emit TicketsDebited(user, amount, reason);
    }

    // ── Admin ─────────────────────────────────────────────────────────────────

    function grantTickets(address user, uint256 amount, bytes32 reason) external onlyOwner {
        ticketBalance[user] += amount;
        emit TicketsGranted(user, amount, reason);
    }

    function setSettlementManager(address manager) external onlyOwner {
        settlementManager = manager;
        emit SettlementManagerUpdated(manager);
    }

    function setPackConfig(uint256 _tickets, uint256 _miles) external onlyOwner {
        ticketsPerPack = _tickets;
        milesPerPack   = _miles;
        emit PackConfigUpdated(_tickets, _miles);
    }

    function setMaxTicketBalance(uint256 max) external onlyOwner {
        maxTicketBalance = max;
    }

    function setAkibaMiles(address _akibaMiles) external onlyOwner {
        if (_akibaMiles == address(0)) revert ZeroAddress();
        akibaMiles = IAkibaMilesBurnable(_akibaMiles);
    }

    // ── Storage gap ───────────────────────────────────────────────────────────
    uint256[50] private __gap;
}

contracts/farkle/GameCreditVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/PausableUpgradeable.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/// @title GameCreditVault
/// @notice USDT-based credit purchase and reward credit accounting.
///
///         Purchased credits — consumed for paid game entry (non-withdrawable by default).
///         Reward credits    — earned from wins, claimable as USDT when enabled.
///
///         Initial pack: 5 credits = 0.50 USDT (1 credit = 0.10 USDT, 6 decimals).
/// @dev UUPS upgradeable.
contract GameCreditVault is
    Initializable,
    OwnableUpgradeable,
    ReentrancyGuardUpgradeable,
    PausableUpgradeable,
    UUPSUpgradeable
{
    using SafeERC20 for IERC20;

    IERC20  public usdt;
    address public settlementManager;
    bool    public claimEnabled;

    struct CreditPack {
        uint256 packId;
        uint256 usdtAmount;    // USDT base units (6 decimals: 500000 = $0.50)
        uint256 creditAmount;
        bool    active;
    }

    mapping(uint256 => CreditPack) public creditPacks;
    mapping(address => uint256)    public gameCreditBalance;
    mapping(address => uint256)    public rewardCreditBalance; // USDT base units
    uint256 public nextPackId;

    event CreditsPurchased(address indexed user, uint256 indexed packId, uint256 usdtAmount, uint256 creditAmount);
    event GameCreditsDebited(address indexed user, uint256 amount, bytes32 indexed reason);
    event RewardCreditsGranted(address indexed user, uint256 amount, bytes32 indexed reason);
    event RewardCreditsClaimed(address indexed user, uint256 amount);
    event CreditPackSet(uint256 indexed packId, uint256 usdtAmount, uint256 creditAmount, bool active);
    event SettlementManagerUpdated(address newManager);
    event ClaimToggled(bool enabled);

    error PackInactive();
    error InsufficientCredits();
    error InsufficientRewardCredits();
    error ClaimDisabled();
    error Unauthorized();
    error ZeroAddress();

    modifier onlySettlement() {
        if (msg.sender != settlementManager) revert Unauthorized();
        _;
    }

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() { _disableInitializers(); }

    function initialize(address _usdt) external initializer {
        if (_usdt == address(0)) revert ZeroAddress();
        __Ownable_init();
        __ReentrancyGuard_init();
        __Pausable_init();
        __UUPSUpgradeable_init();

        usdt = IERC20(_usdt);

        // Pack 0: 5 credits = 0.50 USDT
        creditPacks[0] = CreditPack(0, 500_000, 5, true); // 6-decimal USDT
        nextPackId = 1;
    }

    function _authorizeUpgrade(address) internal override onlyOwner {}

    // ── User actions ──────────────────────────────────────────────────────────

    function buyCredits(uint256 packId) external nonReentrant whenNotPaused {
        CreditPack storage pack = creditPacks[packId];
        if (!pack.active) revert PackInactive();
        usdt.safeTransferFrom(msg.sender, address(this), pack.usdtAmount);
        gameCreditBalance[msg.sender] += pack.creditAmount;
        emit CreditsPurchased(msg.sender, packId, pack.usdtAmount, pack.creditAmount);
    }

    function claimRewardCredits(uint256 amount) external nonReentrant {
        if (!claimEnabled) revert ClaimDisabled();
        if (rewardCreditBalance[msg.sender] < amount) revert InsufficientRewardCredits();
        unchecked { rewardCreditBalance[msg.sender] -= amount; }
        usdt.safeTransfer(msg.sender, amount);
        emit RewardCreditsClaimed(msg.sender, amount);
    }

    // ── Settlement manager actions ────────────────────────────────────────────

    function debitGameCredits(address user, uint256 amount, bytes32 reason) external onlySettlement {
        if (gameCreditBalance[user] < amount) revert InsufficientCredits();
        unchecked { gameCreditBalance[user] -= amount; }
        emit GameCreditsDebited(user, amount, reason);
    }

    function creditRewardCredits(address user, uint256 amount, bytes32 reason) external onlySettlement {
        rewardCreditBalance[user] += amount;
        emit RewardCreditsGranted(user, amount, reason);
    }

    // ── Admin ─────────────────────────────────────────────────────────────────

    function setCreditPack(
        uint256 packId,
        uint256 usdtAmount,
        uint256 creditAmount,
        bool    active
    ) external onlyOwner {
        creditPacks[packId] = CreditPack(packId, usdtAmount, creditAmount, active);
        emit CreditPackSet(packId, usdtAmount, creditAmount, active);
    }

    function addCreditPack(uint256 usdtAmount, uint256 creditAmount) external onlyOwner returns (uint256 packId) {
        packId = nextPackId++;
        creditPacks[packId] = CreditPack(packId, usdtAmount, creditAmount, true);
        emit CreditPackSet(packId, usdtAmount, creditAmount, true);
    }

    function setClaimEnabled(bool enabled) external onlyOwner {
        claimEnabled = enabled;
        emit ClaimToggled(enabled);
    }

    function setSettlementManager(address manager) external onlyOwner {
        settlementManager = manager;
        emit SettlementManagerUpdated(manager);
    }

    function setUsdt(address _usdt) external onlyOwner {
        if (_usdt == address(0)) revert ZeroAddress();
        usdt = IERC20(_usdt);
    }

    function pause()   external onlyOwner { _pause(); }
    function unpause() external onlyOwner { _unpause(); }

    function withdrawUSDT(address to, uint256 amount) external onlyOwner {
        usdt.safeTransfer(to, amount);
    }

    // ── Storage gap ───────────────────────────────────────────────────────────
    uint256[50] private __gap;
}

contracts/farkle/GameRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";

/// @title GameRegistry
/// @notice Registers games and modes. Pure configuration — no funds held.
/// @dev UUPS upgradeable.
contract GameRegistry is Initializable, OwnableUpgradeable, UUPSUpgradeable {

    enum EntryCurrency { NONE, AKIBA_TICKET, GAME_CREDIT, USDT }
    enum RewardType    { NONE, AKIBAMILES, REWARD_CREDIT, MIXED }

    struct Game {
        bytes32 gameId;
        string  name;
        bool    active;
        address resolver;
        uint256 createdAt;
    }

    struct GameMode {
        bytes32        modeId;
        bytes32        gameId;
        string         name;
        uint8          playerCount;
        uint256        targetScore;
        EntryCurrency  entryCurrency;
        uint256        entryAmount;
        RewardType     rewardType;
        bool           active;
    }

    mapping(bytes32 => Game)     public games;
    mapping(bytes32 => GameMode) public gameModes;
    bytes32[] public gameIds;
    bytes32[] public modeIds;

    event GameRegistered(bytes32 indexed gameId, string name, address resolver);
    event GameModeRegistered(bytes32 indexed modeId, bytes32 indexed gameId, string name);
    event GameStatusUpdated(bytes32 indexed gameId, bool active);
    event GameModeStatusUpdated(bytes32 indexed modeId, bool active);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() { _disableInitializers(); }

    function initialize() external initializer {
        __Ownable_init();
        __UUPSUpgradeable_init();
    }

    function _authorizeUpgrade(address) internal override onlyOwner {}

    // ── Mutators ──────────────────────────────────────────────────────────────

    function registerGame(
        bytes32 gameId,
        string calldata name,
        address resolver
    ) external onlyOwner {
        require(games[gameId].createdAt == 0, "already registered");
        games[gameId] = Game(gameId, name, true, resolver, block.timestamp);
        gameIds.push(gameId);
        emit GameRegistered(gameId, name, resolver);
    }

    function setGameActive(bytes32 gameId, bool active) external onlyOwner {
        require(games[gameId].createdAt != 0, "unknown game");
        games[gameId].active = active;
        emit GameStatusUpdated(gameId, active);
    }

    function registerGameMode(
        bytes32        modeId,
        bytes32        gameId,
        string calldata name,
        uint8          playerCount,
        uint256        targetScore,
        EntryCurrency  entryCurrency,
        uint256        entryAmount,
        RewardType     rewardType
    ) external onlyOwner {
        require(games[gameId].createdAt != 0, "unknown game");
        require(gameModes[modeId].gameId == bytes32(0), "mode exists");
        gameModes[modeId] = GameMode(
            modeId, gameId, name, playerCount, targetScore,
            entryCurrency, entryAmount, rewardType, true
        );
        modeIds.push(modeId);
        emit GameModeRegistered(modeId, gameId, name);
    }

    function setGameModeActive(bytes32 modeId, bool active) external onlyOwner {
        require(gameModes[modeId].gameId != bytes32(0), "unknown mode");
        gameModes[modeId].active = active;
        emit GameModeStatusUpdated(modeId, active);
    }

    function setResolver(bytes32 gameId, address resolver) external onlyOwner {
        require(games[gameId].createdAt != 0, "unknown game");
        games[gameId].resolver = resolver;
    }

    // ── Views ─────────────────────────────────────────────────────────────────

    function isGameActive(bytes32 gameId) external view returns (bool) {
        return games[gameId].active;
    }

    function isModeActive(bytes32 modeId) external view returns (bool) {
        return gameModes[modeId].active;
    }

    function getGameCount() external view returns (uint256) { return gameIds.length; }
    function getModeCount() external view returns (uint256) { return modeIds.length; }

    // ── Storage gap ───────────────────────────────────────────────────────────
    uint256[50] private __gap;
}

